def assess(record: dict) -> str:
    required = {'case_id', 'environment', 'observed_ms', 'owner', 'response', 'source', 'stimulus', 'target_ms'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    meets = record["observed_ms"] <= record["target_ms"] and bool(record.get("owner"))
    return "PASS" if meets else 'REJECT_QA_SCENARIO'

valid = {"case_id": 'CASO-LIM-040-1A', **{'source':'ops', 'stimulus':'100 req/s', 'environment':'peak', 'response':'serve', 'observed_ms':280, 'target_ms':300, 'owner':'platform'}}
invalid = {"case_id": 'CASO-LIM-040-1A', **{'source':'ops', 'stimulus':'100 req/s', 'environment':'peak', 'response':'serve', 'observed_ms':1280, 'target_ms':300, 'owner':'platform'}}
incomplete = {k: v for k, v in valid.items() if k != 'owner'}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

